from fastapi import APIRouter, HTTPException

from app.api.deps import DBSession
from app.schemas.report import ReportCreate, ReportResponse
from app.services.report import create_report, get_reports

router = APIRouter(prefix="/reports")


@router.post("", response_model=ReportResponse, status_code=201)
def submit_report(data: ReportCreate, db: DBSession):
    if not data.image_urls:
        raise HTTPException(status_code=422, detail="Cần ít nhất 1 ảnh để gửi báo cáo")
    return create_report(db, data)


@router.get("", response_model=list[ReportResponse])
def list_reports(room_code: str | None = None, db: DBSession = DBSession):
    return get_reports(db, room_code=room_code)

