/* ============================================================
   HOUSEKEEPING REPORT APP — Mobile-first, elderly-friendly
   Design: Warm & trustworthy hotel blue, Nunito rounded font
   ============================================================ */

/* ── Reset ── */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ── Variables ── */
:root {
  --font: 'Nunito', sans-serif;

  --blue:       #4A90FF;
  --blue-dark:  #2F74E0;
  --blue-light: #E8F4FF;
  --blue-bg:    #D6EAFF;
  --blue-muted: rgba(74,144,255,0.15);

  --white:  #FFFFFF;
  --bg:     #F2F6FB;
  --surface:#FFFFFF;

  --text:   #111827;
  --text2:  #374151;
  --text3:  #6B7280;

  --success:#16A34A;
  --success-bg:#DCFCE7;
  --error:  #DC2626;
  --error-bg:#FEF2F2;

  --radius-sm: 12px;
  --radius:    16px;
  --radius-lg: 20px;
  --radius-xl: 26px;

  --shadow-card: 0 4px 20px rgba(74,144,255,0.12);
  --shadow-btn:  0 4px 16px rgba(74,144,255,0.35);

  --transition: 200ms ease;
}

/* ── Base ── */
html, body {
  height: 100%;
  overflow: hidden;
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

/* ── Screen system ── */
.screen {
  position: fixed;
  inset: 0;
  display: none;
  flex-direction: column;
  background: linear-gradient(160deg, #F2F6FB 0%, #FFFFFF 100%);
  overflow: hidden;
  z-index: 1;
  transition: opacity 300ms ease, transform 300ms ease;
}

.screen--active {
  display: flex;
}

.screen--enter {
  opacity: 0;
  transform: translateX(30px);
}

.screen--enter-active {
  opacity: 1;
  transform: translateX(0);
}

.screen--exit {
  opacity: 1;
  transform: translateX(0);
}

.screen--exit-active {
  opacity: 0;
  transform: translateX(-20px);
}

.screen__inner {
  display: flex;
  flex-direction: column;
  height: 100%;
  padding: env(safe-area-inset-top, 0) 0 env(safe-area-inset-bottom, 0) 0;
}

.screen__inner--center {
  align-items: center;
  justify-content: center;
  text-align: center;
  padding: 32px 24px;
  gap: 24px;
}

/* ── Screen 1 top ── */
.screen__top {
  padding: 48px 24px 24px;
  text-align: center;
}

.app-logo {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  margin-bottom: 28px;
}

.app-logo__icon {
  font-size: 36px;
  line-height: 1;
}

.app-logo__name {
  font-size: 22px;
  font-weight: 900;
  color: var(--blue);
  letter-spacing: -0.3px;
}

.page-title {
  font-size: 28px;
  font-weight: 800;
  color: var(--text);
  line-height: 1.2;
  margin-bottom: 8px;
}

.page-sub {
  font-size: 16px;
  color: var(--text3);
  font-weight: 600;
  line-height: 1.5;
}

/* ── Screen body / footer ── */
.screen__body {
  flex: 1;
  overflow-y: auto;
  padding: 16px 16px 0;
  -webkit-overflow-scrolling: touch;
}

.screen__footer {
  padding: 16px 16px calc(16px + env(safe-area-inset-bottom, 0px));
  background: transparent;
}

/* ── Room input card ── */
.input-card {
  background: var(--white);
  border-radius: var(--radius-lg);
  padding: 24px;
  box-shadow: var(--shadow-card);
  margin-top: 8px;
}

.room-input {
  width: 100%;
  height: 72px;
  border: 2.5px solid var(--blue-bg);
  border-radius: var(--radius);
  font-family: var(--font);
  font-size: 32px;
  font-weight: 800;
  text-align: center;
  color: var(--text);
  background: var(--blue-light);
  outline: none;
  letter-spacing: 2px;
  transition: border-color var(--transition), box-shadow var(--transition);
}

.room-input:focus {
  border-color: var(--blue);
  box-shadow: 0 0 0 4px rgba(74,144,255,0.18);
  background: #fff;
}

.room-input::placeholder {
  color: #B0C4DE;
  font-weight: 700;
  letter-spacing: 1px;
}

.field-error {
  margin-top: 10px;
  font-size: 15px;
  font-weight: 700;
  color: var(--error);
  text-align: center;
  background: var(--error-bg);
  padding: 8px 12px;
  border-radius: var(--radius-sm);
}

/* ── Buttons ── */
.btn {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  width: 100%;
  height: 56px;
  border: none;
  border-radius: var(--radius-xl);
  font-family: var(--font);
  font-size: 18px;
  font-weight: 800;
  cursor: pointer;
  transition: transform var(--transition), box-shadow var(--transition), background var(--transition);
  -webkit-tap-highlight-color: transparent;
  user-select: none;
}

.btn--primary {
  background: var(--blue);
  color: #fff;
  box-shadow: var(--shadow-btn);
}

.btn--primary:active {
  transform: scale(0.98);
  background: var(--blue-dark);
  box-shadow: 0 2px 8px rgba(74,144,255,0.3);
}

.btn--disabled,
.btn:disabled {
  background: #B0C4DE !important;
  color: #fff !important;
  box-shadow: none !important;
  cursor: not-allowed;
  pointer-events: none;
}

.btn--lg {
  height: 60px;
  font-size: 20px;
}

.btn--outline {
  background: transparent;
  border: 2px solid var(--blue);
  color: var(--blue);
  box-shadow: none;
}

.btn--sm {
  width: auto;
  height: 40px;
  padding: 0 20px;
  font-size: 15px;
}

.btn__icon {
  font-size: 22px;
}

/* ── Screen header ── */
.screen-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 16px 12px;
  padding-top: calc(16px + env(safe-area-inset-top, 0px));
  gap: 12px;
  background: rgba(242,246,251,0.95);
  backdrop-filter: blur(8px);
  -webkit-backdrop-filter: blur(8px);
  border-bottom: 1px solid rgba(74,144,255,0.08);
}

.screen-header__info {
  flex: 1;
  text-align: center;
}

.screen-header__sub {
  font-size: 13px;
  font-weight: 600;
  color: var(--text3);
  margin-top: 2px;
}

.room-badge {
  display: inline-block;
  background: var(--blue);
  color: #fff;
  font-size: 16px;
  font-weight: 900;
  padding: 4px 16px;
  border-radius: var(--radius-xl);
  letter-spacing: 1px;
}

.photo-counter {
  font-size: 15px;
  font-weight: 800;
  color: var(--blue);
  background: var(--blue-light);
  padding: 4px 12px;
  border-radius: var(--radius-xl);
  min-width: 52px;
  text-align: center;
}

/* ── Back button ── */
.btn-back {
  width: 44px;
  height: 44px;
  border: none;
  background: var(--white);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  flex-shrink: 0;
  -webkit-tap-highlight-color: transparent;
  transition: transform var(--transition);
}

.btn-back:active { transform: scale(0.92); }

.btn-back svg {
  width: 20px;
  height: 20px;
  color: var(--text2);
}

/* ── Camera screen ── */
.camera-body {
  padding: 12px 12px 0;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.viewfinder {
  position: relative;
  width: 100%;
  aspect-ratio: 4/3;
  border-radius: var(--radius-lg);
  overflow: hidden;
  background: #1a1a2e;
  flex-shrink: 0;
}

.camera-video {
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
}

.viewfinder__overlay {
  position: absolute;
  inset: 0;
  pointer-events: none;
}

.viewfinder__corner {
  position: absolute;
  width: 24px;
  height: 24px;
  border-color: rgba(255,255,255,0.8);
  border-style: solid;
}

.viewfinder__corner--tl { top: 12px; left: 12px; border-width: 3px 0 0 3px; border-radius: 4px 0 0 0; }
.viewfinder__corner--tr { top: 12px; right: 12px; border-width: 3px 3px 0 0; border-radius: 0 4px 0 0; }
.viewfinder__corner--bl { bottom: 12px; left: 12px; border-width: 0 0 3px 3px; border-radius: 0 0 0 4px; }
.viewfinder__corner--br { bottom: 12px; right: 12px; border-width: 0 3px 3px 0; border-radius: 0 0 4px 0; }

.camera-fallback {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  background: #1a1a2e;
  color: #fff;
  padding: 24px;
}

.camera-fallback__icon { font-size: 48px; }

.camera-fallback__text {
  font-size: 15px;
  font-weight: 600;
  text-align: center;
  line-height: 1.5;
  color: rgba(255,255,255,0.85);
}

/* ── Thumbnails ── */
.thumbnails {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 4px 2px 8px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
  min-height: 76px;
  align-items: center;
}

.thumbnails::-webkit-scrollbar { display: none; }

.thumb {
  position: relative;
  width: 68px;
  height: 68px;
  border-radius: var(--radius-sm);
  overflow: visible;
  flex-shrink: 0;
}

.thumb img {
  width: 68px;
  height: 68px;
  object-fit: cover;
  border-radius: var(--radius-sm);
  border: 2.5px solid var(--blue);
  display: block;
}

.thumb__delete {
  position: absolute;
  top: -8px;
  right: -8px;
  width: 24px;
  height: 24px;
  background: var(--error);
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 13px;
  font-weight: 800;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  line-height: 1;
  box-shadow: 0 2px 6px rgba(0,0,0,0.2);
  -webkit-tap-highlight-color: transparent;
}

/* ── Camera controls ── */
.camera-footer {
  padding: 12px 24px calc(12px + env(safe-area-inset-bottom, 0px));
  background: rgba(242,246,251,0.95);
  border-top: 1px solid rgba(74,144,255,0.08);
}

.camera-controls {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.btn-shutter {
  position: relative;
  width: 80px;
  height: 80px;
  border: none;
  background: transparent;
  cursor: pointer;
  -webkit-tap-highlight-color: transparent;
  flex-shrink: 0;
}

.btn-shutter:active .btn-shutter__ring {
  transform: scale(0.95);
}

.btn-shutter:active .btn-shutter__dot {
  transform: translate(-50%, -50%) scale(0.85);
}

.btn-shutter__ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
  border: 4px solid var(--blue);
  background: rgba(74,144,255,0.08);
  transition: transform var(--transition);
}

.btn-shutter__dot {
  position: absolute;
  top: 50%;
  left: 50%;
  width: 56px;
  height: 56px;
  background: var(--blue);
  border-radius: 50%;
  transform: translate(-50%, -50%);
  box-shadow: var(--shadow-btn);
  transition: transform var(--transition);
}

.btn-icon {
  width: 52px;
  height: 52px;
  border: none;
  background: var(--white);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  box-shadow: 0 2px 12px rgba(0,0,0,0.1);
  -webkit-tap-highlight-color: transparent;
  transition: transform var(--transition), opacity var(--transition);
  flex-shrink: 0;
}

.btn-icon:active { transform: scale(0.92); }

.btn-icon svg {
  width: 22px;
  height: 22px;
  color: var(--text2);
}

.btn-icon--sm {
  width: 52px;
  height: 52px;
}

.btn-icon--accent {
  background: var(--blue);
  box-shadow: var(--shadow-btn);
}

.btn-icon--accent svg {
  color: #fff;
}

.btn-icon--accent:disabled,
.btn-icon--accent[data-disabled="true"] {
  background: #B0C4DE;
  box-shadow: none;
  opacity: 0.7;
  pointer-events: none;
}

.camera-hint {
  font-size: 13px;
  font-weight: 700;
  color: var(--text3);
  text-align: center;
  margin-top: 8px;
}

/* ── Report screen cards ── */
.report-body {
  display: flex;
  flex-direction: column;
  gap: 16px;
  padding-bottom: 16px;
}

.card {
  border-radius: var(--radius-lg);
  padding: 18px;
}

.card--blue {
  background: var(--blue-light);
  box-shadow: var(--shadow-card);
}

.card--white {
  background: var(--white);
  box-shadow: 0 2px 12px rgba(0,0,0,0.07);
}

.card__label {
  font-size: 15px;
  font-weight: 800;
  color: var(--text2);
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.card__label-icon { font-size: 18px; }

.photo-tag {
  margin-left: auto;
  font-size: 13px;
  font-weight: 700;
  background: var(--blue);
  color: #fff;
  padding: 2px 10px;
  border-radius: var(--radius-xl);
}

/* ── Photos strip ── */
.photos-strip {
  display: flex;
  gap: 10px;
  overflow-x: auto;
  padding: 2px 0 4px;
  -webkit-overflow-scrolling: touch;
  scrollbar-width: none;
}

.photos-strip::-webkit-scrollbar { display: none; }

.photo-thumb {
  width: 80px;
  height: 80px;
  border-radius: var(--radius-sm);
  object-fit: cover;
  flex-shrink: 0;
  border: 2.5px solid var(--blue-bg);
}

/* ── Voice recording ── */
.voice-card {}

.voice-area {
  display: flex;
  align-items: center;
  gap: 20px;
  padding: 8px 0 16px;
}

.btn-mic {
  position: relative;
  width: 80px;
  height: 80px;
  border: none;
  background: var(--blue-light);
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
  flex-shrink: 0;
  -webkit-tap-highlight-color: transparent;
  transition: background var(--transition), transform var(--transition);
}

.btn-mic:active { transform: scale(0.94); }

.btn-mic--recording {
  background: #FEE2E2;
  animation: mic-pulse-bg 1.2s ease-in-out infinite;
}

@keyframes mic-pulse-bg {
  0%, 100% { background: #FEE2E2; }
  50% { background: #FECACA; }
}

.btn-mic__pulse {
  position: absolute;
  inset: -6px;
  border-radius: 50%;
  border: 3px solid var(--blue);
  opacity: 0;
  transform: scale(0.8);
  transition: opacity var(--transition);
}

.btn-mic--recording .btn-mic__pulse {
  animation: pulse-ring 1.4s ease-out infinite;
  border-color: var(--error);
}

@keyframes pulse-ring {
  0% { transform: scale(0.85); opacity: 0.8; }
  100% { transform: scale(1.4); opacity: 0; }
}

.btn-mic__icon {
  font-size: 32px;
  line-height: 1;
  position: relative;
  z-index: 1;
}

.voice-status {
  font-size: 16px;
  font-weight: 700;
  color: var(--text2);
  flex: 1;
  line-height: 1.4;
}

.voice-status--recording {
  color: var(--error);
}

.voice-text-wrap { width: 100%; }

.voice-text {
  width: 100%;
  font-family: var(--font);
  font-size: 16px;
  font-weight: 600;
  color: var(--text2);
  background: var(--bg);
  border: 2px solid var(--blue-bg);
  border-radius: var(--radius-sm);
  padding: 12px 14px;
  resize: none;
  outline: none;
  line-height: 1.5;
