/**
 * Housekeeping Report App
 * 4-screen SPA: Room Input → Camera → Report → Success
 */

// ── App State ──────────────────────────────────────────────
const state = {
  roomCode: '',
  photos: [],       // Array of { blob, dataUrl, s3Url }
  voiceNote: '',
  cameraStream: null,
  facingMode: 'environment',
  recognition: null,
  isRecording: false,
};

// ── Helpers ────────────────────────────────────────────────
function escapeHtml(text) {
  const div = document.createElement('div');
  div.textContent = String(text);
  return div.innerHTML;
}

let toastTimer = null;
function showToast(msg, duration = 2500) {
  const toast = document.getElementById('toast');
  toast.textContent = msg;
  toast.classList.remove('hidden');
  toast.classList.add('toast--visible');
  clearTimeout(toastTimer);
  toastTimer = setTimeout(() => {
    toast.classList.remove('toast--visible');
    setTimeout(() => toast.classList.add('hidden'), 260);
  }, duration);
}

function navigateTo(screenId) {
  document.querySelectorAll('.screen').forEach(s => {
    s.classList.remove('screen--active');
  });
  const target = document.getElementById(screenId);
  if (target) target.classList.add('screen--active');
}

// ── SCREEN 1: Room Input ───────────────────────────────────
const roomInput   = document.getElementById('room-input');
const btnRoomNext = document.getElementById('btn-room-next');
const roomError   = document.getElementById('room-error');

roomInput.addEventListener('input', () => {
  const val = roomInput.value.trim();
  roomError.classList.add('hidden');
  if (val.length > 0) {
    btnRoomNext.disabled = false;
    btnRoomNext.classList.remove('btn--disabled');
  } else {
    btnRoomNext.disabled = true;
    btnRoomNext.classList.add('btn--disabled');
  }
});

roomInput.addEventListener('keydown', (e) => {
  if (e.key === 'Enter' && !btnRoomNext.disabled) goToCamera();
});

btnRoomNext.addEventListener('click', goToCamera);

function goToCamera() {
  const val = roomInput.value.trim();
  if (!val) {
    roomError.classList.remove('hidden');
    roomInput.focus();
    return;
  }
  state.roomCode = val.toUpperCase();
  state.photos = [];

  // Update badges
  document.getElementById('camera-room-badge').textContent = 'PHÒNG ' + state.roomCode;
  document.getElementById('report-room-badge').textContent = 'PHÒNG ' + state.roomCode;

  navigateTo('screen-camera');
  startCamera();
}

// Auto-focus room input on load
window.addEventListener('load', () => {
  setTimeout(() => roomInput.focus(), 300);
});

// ── SCREEN 2: Camera ───────────────────────────────────────
const cameraVideo    = document.getElementById('camera-video');
const captureCanvas  = document.getElementById('capture-canvas');
const btnShutter     = document.getElementById('btn-shutter');
const btnCameraBack  = document.getElementById('btn-camera-back');
const btnSwitchCam   = document.getElementById('btn-switch-camera');
const btnCameraNext  = document.getElementById('btn-camera-next');
const thumbnailsEl   = document.getElementById('thumbnails');
const photoCounter   = document.getElementById('photo-counter');
const cameraFallback = document.getElementById('camera-fallback');
const cameraHint     = document.getElementById('camera-hint');
const btnRetryCamera = document.getElementById('btn-retry-camera');

async function startCamera() {
  if (state.cameraStream) stopCamera();
  try {
    cameraFallback.classList.add('hidden');
    cameraVideo.style.display = 'block';
    const stream = await navigator.mediaDevices.getUserMedia({
      video: { facingMode: state.facingMode, width: { ideal: 1280 }, height: { ideal: 960 } },
      audio: false,
    });
    state.cameraStream = stream;
    cameraVideo.srcObject = stream;
    await cameraVideo.play();
  } catch (err) {
    console.warn('Camera error:', err);
    cameraVideo.style.display = 'none';
    cameraFallback.classList.remove('hidden');
  }
}

function stopCamera() {
  if (state.cameraStream) {
    state.cameraStream.getTracks().forEach(t => t.stop());
    state.cameraStream = null;
  }
  cameraVideo.srcObject = null;
}

btnRetryCamera.addEventListener('click', startCamera);

btnSwitchCam.addEventListener('click', () => {
  state.facingMode = state.facingMode === 'environment' ? 'user' : 'environment';
  startCamera();
});

btnCameraBack.addEventListener('click', () => {
  stopCamera();
  navigateTo('screen-room');
  roomInput.focus();
});

btnShutter.addEventListener('click', capturePhoto);

async function capturePhoto() {
  if (state.photos.length >= 3) {
    showToast('Tối đa 3 ảnh');
    return;
  }

  // Flash effect
  btnShutter.style.opacity = '0.5';
  setTimeout(() => (btnShutter.style.opacity = '1'), 150);

  const video = cameraVideo;
  captureCanvas.width  = video.videoWidth  || 1280;
  captureCanvas.height = video.videoHeight || 960;
  const ctx = captureCanvas.getContext('2d');
  ctx.drawImage(video, 0, 0);

  const dataUrl = captureCanvas.toDataURL('image/jpeg', 0.85);
  const blob    = await (await fetch(dataUrl)).blob();

  state.photos.push({ blob, dataUrl, s3Url: null });
  updateCameraUI();

  if (state.photos.length === 3) {
    // Auto-navigate after brief delay
    setTimeout(goToReport, 600);
  }
}

function updateCameraUI() {
  const count = state.photos.length;
  photoCounter.textContent = `${count} / 3`;

  // Update hint
  if (count === 0) {
    cameraHint.textContent = 'Chụp ít nhất 1 ảnh để tiếp tục';
  } else if (count < 3) {
    cameraHint.textContent = `Đã chụp ${count} ảnh — có thể tiếp tục hoặc chụp thêm`;
  } else {
    cameraHint.textContent = 'Đã đủ 3 ảnh — đang chuyển trang...';
  }

  // Next button state
  if (count >= 1) {
    btnCameraNext.removeAttribute('data-disabled');
    btnCameraNext.disabled = false;
    btnCameraNext.classList.remove('btn-icon--disabled');
  } else {
    btnCameraNext.setAttribute('data-disabled', 'true');
    btnCameraNext.disabled = false; // allow click but show toast
  }

  // Thumbnails
  thumbnailsEl.innerHTML = state.photos.map((p, i) => `
    <div class="thumb">
      <img src="${escapeHtml(p.dataUrl)}" alt="Ảnh ${i + 1}">
      <button class="thumb__delete" data-index="${i}" aria-label="Xóa ảnh ${i + 1}">✕</button>
    </div>
  `).join('');

  thumbnailsEl.querySelectorAll('.thumb__delete').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const idx = parseInt(e.currentTarget.dataset.index, 10);
      state.photos.splice(idx, 1);
      updateCameraUI();
    });
  });
}

btnCameraNext.addEventListener('click', () => {
  if (state.photos.length === 0) {
    showToast('Chụp ít nhất 1 ảnh để tiếp tục');
    return;
  }
  goToReport();
});

function goToReport() {
  stopCamera();
  renderReportScreen();
  navigateTo('screen-report');
}

// ── SCREEN 3: Report ───────────────────────────────────────
const btnReportBack = document.getElementById('btn-report-back');
const btnSubmit     = document.getElementById('btn-submit');
const btnMic        = document.getElementById('btn-mic');
const micPulse      = document.getElementById('mic-pulse');
const voiceStatus   = document.getElementById('voice-status');
const voiceText     = document.getElementById('voice-text');
const reportPhotos  = document.getElementById('report-photos');
const reportCount   = document.getElementById('report-photo-count');
const reportError   = document.getElementById('report-error');

btnReportBack.addEventListener('click', () => {
  stopVoice();
  navigateTo('screen-camera');
  startCamera();
});

function renderReportScreen() {
  reportCount.textContent = state.photos.length + ' ảnh';
  reportPhotos.innerHTML = state.photos
    .map(p => `<img class="photo-thumb" src="${escapeHtml(p.dataUrl)}" alt="Ảnh phòng">`)
    .join('');
  reportError.classList.add('hidden');
  voiceText.value = state.voiceNote || '';
  setupSpeechRecognition();
}

// ── Voice Recognition ──────────────────────────────────────
function setupSpeechRecognition() {
  const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
  if (!SpeechRecognition) {
    voiceStatus.textContent = 'Trình duyệt không hỗ trợ ghi âm';
    btnMic.style.opacity = '0.4';
    btnMic.style.pointerEvents = 'none';
    return;
  }

  if (state.recognition) {
    state.recognition.abort();
    state.recognition = null;
  }

  const rec = new SpeechRecognition();
  rec.lang = 'vi-VN';
  rec.continuous = true;
  rec.interimResults = true;

  let finalTranscript = voiceText.value;

  rec.onresult = (e) => {
    let interim = '';
    for (let i = e.resultIndex; i < e.results.length; i++) {
      if (e.results[i].isFinal) {
        finalTranscript += e.results[i][0].transcript + ' ';
      } else {
        interim += e.results[i][0].transcript;
      }
    }
    voiceText.value = finalTranscript + interim;
  };

  rec.onend = () => {
    if (state.isRecording) {
      // Restart if still recording
      try { rec.start(); } catch (_) {}
    } else {
      state.voiceNote = voiceText.value;
      setMicState(false);
    }
  };

  rec.onerror = (e) => {
    if (e.error !== 'aborted') {
      console.warn('Speech error:', e.error);
      showToast('Lỗi ghi âm: ' + e.error);
    }
    state.isRecording = false;
    setMicState(false);
  };

  state.recognition = rec;
}

btnMic.addEventListener('click', () => {
  if (state.isRecording) {
    stopVoice();
  } else {
    startVoice();
  }
});

function startVoice() {
  if (!state.recognition) setupSpeechRecognition();
  if (!state.recognition) return;
  state.isRecording = true;
  try {
    state.recognition.start();
    setMicState(true);
  } catch (e) {
    console.warn(e);
    state.isRecording = false;
    setMicState(false);
  }
}

function stopVoice() {
  state.isRecording = false;
  if (state.recognition) {
    try { state.recognition.stop(); } catch (_) {}
  }
  state.voiceNote = voiceText.value;
  setMicState(false);
}

function setMicState(recording) {
  if (recording) {
    btnMic.classList.add('btn-mic--recording');
    voiceStatus.textContent = '⏺ Đang ghi âm... Nhấn để dừng';
    voiceStatus.classList.add('voice-status--recording');
  } else {
    btnMic.classList.remove('btn-mic--recording');
    voiceStatus.textContent = voiceText.value.trim()
      ? '✅ Nhấn để ghi âm thêm'
      : 'Nhấn để ghi âm';
    voiceStatus.classList.remove('voice-status--recording');
  }
}

voiceText.addEventListener('input', () => {
  state.voiceNote = voiceText.value;
});

// ── Submit ─────────────────────────────────────────────────
btnSubmit.addEventListener('click', submitReport);

async function submitReport() {
  reportError.classList.add('hidden');

  if (state.photos.length === 0) {
    reportError.textContent = 'Cần ít nhất 1 ảnh để gửi báo cáo';
    reportError.classList.remove('hidden');
    return;
  }

  stopVoice();

  btnSubmit.disabled = true;
  btnSubmit.innerHTML = '<span style="font-size:18px">⏳</span> Đang gửi...';

  try {
    // Upload photos to S3
    const imageUrls = await uploadPhotos();

    // Submit report to backend
    const result = await api.post('/api/reports', {
      room_code: state.roomCode,
      voice_note: voiceText.value.trim() || null,
      image_urls: imageUrls,
    });

    // Show success
    showSuccess(result);

  } catch (err) {
    console.error('Submit error:', err);
    reportError.textContent = 'Lỗi gửi báo cáo: ' + (err.message || 'Thử lại');
    reportError.classList.remove('hidden');
  } finally {
    btnSubmit.disabled = false;
    btnSubmit.innerHTML = '<span class="btn__icon">📤</span> GỬI BÁO CÁO';
  }
}

async function uploadPhotos() {
  const urls = [];
  for (let i = 0; i < state.photos.length; i++) {
    const photo = state.photos[i];

    // If already uploaded, skip
    if (photo.s3Url) {
      urls.push(photo.s3Url);
      continue;
    }

    const filename = `housekeeping/${state.roomCode}_${Date.now()}_${i}.jpg`;

    // Get presigned URL
    const { upload_url, file_url } = await api.post('/api/upload/presigned-url', { filename });

    // PUT to S3
    const res = await fetch(upload_url, {
      method: 'PUT',
      body: photo.blob,
      headers: { 'Content-Type': 'image/jpeg' },
    });

    if (!res.ok) throw new Error(`Upload ảnh ${i + 1} thất bại`);

    photo.s3Url = file_url;
    urls.push(file_url);
  }
  return urls;
}

// ── SCREEN 4: Success ──────────────────────────────────────
const btnNewRoom = document.getElementById('btn-new-room');

function showSuccess(result) {
  document.getElementById('success-room').textContent = state.roomCode;
  const meta = document.getElementById('success-meta');
  if (result && result.submitted_at) {
    const d = new Date(result.submitted_at);
    meta.textContent = d.toLocaleString('vi-VN', {
      hour: '2-digit', minute: '2-digit',
      day: '2-digit', month: '2-digit', year: 'numeric',
    });
  } else {
    meta.textContent = '';
  }
  navigateTo('screen-success');
}

btnNewRoom.addEventListener('click', resetApp);

function resetApp() {
  state.roomCode = '';
  state.photos = [];
  state.voiceNote = '';
  stopVoice();

  roomInput.value = '';
  btnRoomNext.disabled = true;
  btnRoomNext.classList.add('btn--disabled');
  voiceText.value = '';
  thumbnailsEl.innerHTML = '';
  updateCameraUI();

  navigateTo('screen-room');
  setTimeout(() => roomInput.focus(), 300);
}

